public int minPairSum(int[] nums) {
    Arrays.sort(nums);
    int maxSum = 0;
    for (int i = 0; i < nums.length / 2; i++)
        maxSum = Math.max(maxSum, nums[i] + nums[nums.length - 1 - i]);
    return maxSum;
}
```

